import*as Browser from"@hyperjump/browser";import{Validation}from"../experimental.js";import{toAbsoluteUri}from"../common.js";const id="https://json-schema.org/keyword/dynamicRef",compile=async(r,o)=>{var i=Browser.value(r),r=await Browser.get(r.document.baseUri,r);return await Validation.compile(r,o),i},interpret=(r,o,i)=>{if(r in i.dynamicAnchors)return Validation.interpret(i.dynamicAnchors[r],o,i);throw Error(`No dynamic anchor found for "${r}"`)},simpleApplicator=!0,plugin={beforeSchema(r,o,i){i.dynamicAnchors={...i.ast.metaData[toAbsoluteUri(r)].dynamicAnchors,...i.dynamicAnchors}},beforeKeyword(r,o,i,e){i.dynamicAnchors=e.dynamicAnchors}};export default{id:id,compile:compile,interpret:interpret,simpleApplicator:simpleApplicator,plugin:plugin};